// Merge a basic block with its unique successor when that successor has
// exactly one predecessor (this BB).  Returns true if a merge occurred.
bool
mergeWithSingleSuccessor(BasicBlock& BB)
{
  auto term = BB.getTerminator();
  auto br = dyn_cast<BranchInst>(term);
  if (!br || !br->isUnconditional())
    return false;
  auto succ = br->getSuccessor(0);
  if (succ == &BB)
    return false;
  if (succ->getSinglePredecessor() != &BB)
    return false;
  // Can't merge if successor starts with PHIs (would be redundant after
  // single-predecessor anyway, but handle conservatively).
  if (isa<PHINode>(&succ->front())) {
    // Replace each PHI with its single incoming value.
    while (auto phi = dyn_cast<PHINode>(&succ->front())) {
      Value* v = phi->getIncomingValueForBlock(&BB);
      phi->replaceAllUsesWith(v);
      phi->eraseFromParent();
    }
  }
  // Remove terminator, then splice succ's instructions onto BB.
  br->eraseFromParent();
  BB.splice(BB.end(), succ);
  // Rewrite predecessors of the (now removed) succ in successors' PHIs.
  succ->replaceAllUsesWith(&BB);
  succ->eraseFromParent();
  return true;
}

